vim.cmd("highlight clear")
if vim.fn.exists("syntax_on") then vim.cmd("syntax reset") end
vim.g.colors_name = "noctalia"

local c = {
  bg          = "{{colors.surface.default.hex}}",
  bg_variant  = "{{colors.surface_variant.default.hex}}",
  fg          = "{{colors.on_surface.default.hex}}",
  fg_muted    = "{{colors.on_surface_variant.default.hex}}",
  primary     = "{{colors.primary.default.hex}}",
  secondary   = "{{colors.secondary.default.hex}}",
  tertiary    = "{{colors.tertiary.default.hex}}",
  error       = "{{colors.error.default.hex}}",
  outline     = "{{colors.outline.default.hex}}",
  on_primary  = "{{colors.on_primary.default.hex}}",
}

local function hi(group, opts)
  vim.api.nvim_set_hl(0, group, opts)
end

-- Editor chrome
hi("Normal",        { fg = c.fg,       bg = c.bg })
hi("NormalFloat",   { fg = c.fg,       bg = c.bg_variant })
hi("LineNr",        { fg = c.outline })
hi("CursorLine",    { bg = c.bg_variant })
hi("CursorLineNr",  { fg = c.primary,  bold = true })
hi("SignColumn",    { bg = c.bg })
hi("ColorColumn",   { bg = c.bg_variant })
hi("VertSplit",     { fg = c.outline })
hi("WinSeparator",  { fg = c.outline })
hi("StatusLine",    { fg = c.fg,       bg = c.bg_variant })
hi("StatusLineNC",  { fg = c.fg_muted, bg = c.bg_variant })
hi("Pmenu",         { fg = c.fg,       bg = c.bg_variant })
hi("PmenuSel",      { fg = c.on_primary, bg = c.primary })
hi("PmenuSbar",     { bg = c.bg_variant })
hi("PmenuThumb",    { bg = c.outline })

-- Selection / search
hi("Visual",        { bg = c.bg_variant })
hi("Search",        { fg = c.on_primary, bg = c.secondary })
hi("IncSearch",     { fg = c.on_primary, bg = c.primary })

-- Diagnostics
hi("DiagnosticError", { fg = c.error })
hi("DiagnosticWarn",  { fg = c.secondary })
hi("DiagnosticInfo",  { fg = c.tertiary })
hi("DiagnosticHint",  { fg = c.fg_muted })

-- Syntax
hi("Comment",     { fg = c.outline,   italic = true })
hi("Constant",    { fg = c.tertiary })
hi("String",      { fg = c.secondary })
hi("Identifier",  { fg = c.fg })
hi("Function",    { fg = c.primary })
