hi("Operator",    { fg = c.fg_muted })
hi("Type",        { fg = c.tertiary })
hi("Special",     { fg = c.secondary })
hi("PreProc",     { fg = c.tertiary })
hi("Error",       { fg = c.error })
hi("Todo",        { fg = c.on_primary, bg = c.secondary, bold = true })

-- Treesitter (links to base groups, overrides where needed)
hi("@variable",           { fg = c.fg })
hi("@variable.builtin",   { fg = c.tertiary })
hi("@function",           { fg = c.primary })
hi("@function.builtin",   { fg = c.primary,   italic = true })
hi("@keyword",            { fg = c.primary,   bold = true })
hi("@string",             { fg = c.secondary })
hi("@comment",            { fg = c.outline,   italic = true })
hi("@type",               { fg = c.tertiary })
hi("@type.builtin",       { fg = c.tertiary,  italic = true })
